// ========== м—җлҹ¬ кІҪкі„ м»ҙнҸ¬л„ҢнҠё ==========
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  componentDidCatch(error, errorInfo) {
    console.error('ErrorBoundary caught:', error, errorInfo);
    this.setState({ errorStack: errorInfo?.componentStack || '' });
  }
  render() {
    if (this.state.hasError) {
      return this.props.fallback || (
        <div style={{padding:'32px', textAlign:'center'}}>
          <h2 style={{color:'#dc2626', fontWeight:'bold', fontSize:'18px', marginBottom:'16px'}}>мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ</h2>
          <p style={{color:'#dc2626', marginBottom:'8px', fontSize:'13px', background:'#fef2f2', padding:'12px', borderRadius:'8px', textAlign:'left', wordBreak:'break-all'}}>{this.state.error?.message || 'м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ'}</p>
          {this.state.errorStack && <p style={{color:'#9ca3af', marginBottom:'8px', fontSize:'10px', background:'#f9fafb', padding:'8px', borderRadius:'6px', textAlign:'left', wordBreak:'break-all', maxHeight:'120px', overflow:'auto', whiteSpace:'pre-wrap'}}>{this.state.errorStack.slice(0, 500)}</p>}
          <p style={{color:'#9ca3af', marginBottom:'16px', fontSize:'11px'}}>мқҙ л©”мӢңм§ҖлҘј м„ мғқлӢҳк»ҳ ліҙм—¬мЈјм„ёмҡ”</p>
          <div style={{display:'flex', gap:'8px', justifyContent:'center'}}>
            <button onClick={() => { this.setState({ hasError: false, error: null }); window.location.reload(); }}
              style={{padding:'10px 20px', background:'#2563eb', color:'white', borderRadius:'8px', border:'none', cursor:'pointer', fontWeight:'bold'}}>
              мғҲлЎңкі м№Ё
            </button>
            <button onClick={() => { localStorage.clear(); window.location.href = '/'; }}
              style={{padding:'10px 20px', background:'#6b7280', color:'white', borderRadius:'8px', border:'none', cursor:'pointer'}}>
              мәҗмӢң мҙҲкё°нҷ”
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

