      <nav style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
        background: scrolled ? 'rgba(255,255,255,0.96)' : 'transparent',
        backdropFilter: scrolled ? 'blur(12px)' : 'none',
        borderBottom: scrolled ? '1px solid rgba(0,0,0,0.08)' : 'none',
        transition: 'all 0.3s ease'
      }}>
        <div style={{ maxWidth: 1200, margin: '0 auto', padding: '0 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: 64 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={{ fontSize: 26 }}>рҹ”ө</span>
            <div>
              <span style={{ fontSize: 17, fontWeight: 900, color: scrolled ? '#1e3a5f' : '#fff', fontFamily: "'Noto Serif KR', serif", letterSpacing: '-0.5px' }}>{lc.nav_name}</span>
              <span style={{ fontSize: 13, color: scrolled ? '#60a5fa' : '#93c5fd', fontWeight: 600, marginLeft: 6 }}>{lc.nav_sub}</span>
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <a href="#features" style={{ fontSize: 13, color: scrolled ? '#475569' : '#e2e8f0', fontWeight: 500, textDecoration: 'none', padding: '6px 12px', display: 'none' }}
              className="nav-link">нҠ№мһҘм җ</a>
            <a href="#programs" style={{ fontSize: 13, color: scrolled ? '#475569' : '#e2e8f0', fontWeight: 500, textDecoration: 'none', padding: '6px 12px', display: 'none' }}
              className="nav-link">н”„лЎңк·ёлһЁ</a>
            <button
              onClick={() => goMode('select')}
              style={{
                padding: '9px 22px', borderRadius: 10, fontWeight: 700, fontSize: 14,
                background: scrolled ? 'linear-gradient(135deg, #1e40af, #3730a3)' : 'rgba(255,255,255,0.18)',
                backdropFilter: 'blur(8px)',
                color: '#fff', border: scrolled ? 'none' : '1.5px solid rgba(255,255,255,0.4)',
                cursor: 'pointer', transition: 'all 0.2s'
              }}>
              лЎңк·ёмқё
            </button>
          </div>
        </div>
      </nav>

      {/* ===== HERO м„№м…ҳ ===== */}
