        { title: 'вҡЎ 3мӣ” мІ« мӢңн—ҳ, мқҙкІғл§Ң м•Ңл©ҙ 100м җ?', site: 'м—җл“Җм§„', url: eduSites.edujin },
        { title: 'рҹ“қ мҲҳн•ҷ л…ёнҠё м •лҰ¬лІ•, 1л“ұкёүмқҖ лӢӨлҘҙлӢӨ!', site: 'EBS көҗмңЎлүҙмҠӨ', url: eduSites.ebsNews },
        { title: 'рҹ”Қ мҳӨлӢөл…ёнҠёмқҳ м§„мӢӨ, мқҙл ҮкІҢ н•ҙм•ј нҡЁкіјмһҲлӢӨ', site: 'лҢҖн•ҷм Җл„җ', url: eduSites.dhnews }
