                  problemStats.forEach(s => { Object.entries(s.wrongTypeCount).forEach(([k,v]) => { totalCounts[k] = (totalCounts[k]||0)+v; }); });
                  const sorted = Object.entries(totalCounts).sort((a,b)=>b[1]-a[1]);
                  const maxCount = sorted[0]?.[1] || 1;
                  const labels = { careless:'рҹҳ… лӢЁмҲңмӢӨмҲҳ', concept:'рҹ“ҡ к°ңл…җлҜёмҲҷ', understanding:'рҹӨ” мқҙн•ҙл¶ҖмЎұ', formula:'рҹ“җ кіөмӢқмҳӨлҘҳ', process:'рҹ“қ н’ҖмқҙмҳӨлҘҳ', time:'вҸ° мӢңк°„л¶ҖмЎұ', reading:'рҹ‘Җ м•ҲмқҪмқҢ' };
                  if (sorted.length === 0) return <p className="text-gray-400 text-sm text-center">мҳӨлӢө мң нҳ• лҚ°мқҙн„° м—ҶмқҢ</p>;
