        alert(`вң… ${transferStudent} н•ҷмғқмқҳ лӢҙлӢ№ м„ мғқлӢҳмқҙ ${targetTeacher}(мңј)лЎң ліҖкІҪлҗҳм—ҲмҠөлӢҲлӢӨ.`);
