                                                            const ans = [...(t.testAnswers || [])];
                                                            ans[idx] = btn.val;
                                                            t.testAnswers = ans;
                                                            // л°°м җ кё°л°ҳ м җмҲҳ мһ¬кі„мӮ°
                                                            const pts = t.problemPoints || [];
