        { value: 3, text: 'мҷң нӢҖл ёлҠ”м§Җ нҷ•мқёмқҖ н–ҲлӢӨ', emoji: 'рҹ§җ' },
        { value: 4, text: 'нӢҖлҰ° мқҙмң лҘј л¶„м„қн•ҳкі  лӢӨмӢң н’Җм–ҙлҙӨлӢӨ', emoji: 'рҹ“қ' },
        { value: 5, text: 'нӢҖлҰ° кІҢ мҳӨнһҲл Ө л°°мҡё кё°нҡҢлқјкі  мғқк°Ғн–ҲлӢӨ', emoji: 'рҹҢұ' }
