        { value: 4, text: 'лҚ” м•Ңкі  мӢ¶мқҖ кІғл“Өмқҙ мһҲм—ҲлӢӨ', emoji: 'рҹ§җ' },
        { value: 5, text: 'нқҘлҜёлЎңмҡҙ м җмқ„ л°ңкІ¬н•ҙм„ң лҚ” нҢҢкі  мӢ¶м—ҲлӢӨ', emoji: 'рҹӨ©' }
